# Most engines DO accept request-time JSON Schema. The issue is
# what you can express — anything outside the engine's grammar zoo
# (a domain protocol, a learned parser, a runtime state machine)
# requires an engine fork.
curl https://api.example.com/v1/responses \
  -d '{
    "model": "qwen3-0.6b",
    "input": "Extract {name, email, age} from this bio: ...",
    "response_format": {
      "type": "json_schema",
      "json_schema": { "name": "Contact", "schema": { ... } }
    }
  }'

